import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuth } from '../contexts/AuthContext'
import { Eye, EyeOff, Scan, AlertCircle, ArrowRight } from 'lucide-react'
import toast from 'react-hot-toast'

const HERO_IMG = "data:image/jpeg;base64,"

export default function LoginPage() {
  const { login } = useAuth()
  const navigate = useNavigate()
  const [form, setForm] = useState({ username: '', password: '' })
  const [show, setShow] = useState(false)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  const handle = e => setForm(p => ({ ...p, [e.target.name]: e.target.value }))

  const submit = async e => {
    e.preventDefault()
    setError('')
    setLoading(true)
    try {
      const user = await login(form.username, form.password)
      toast.success(`Welcome, ${user.name || user.username}!`)
      navigate(user.role === 'admin' ? '/admin' : '/dashboard', { replace: true })
    } catch (err) {
      setError(err.message)
    } finally {
      setLoading(false)
    }
  }

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      background: '#080b11',
      fontFamily: 'Syne, sans-serif',
    }}>

      {/* ── LEFT PANEL ── */}
      <div style={{
        flex: 1,
        position: 'relative',
        background: '#080b11',
        overflow: 'hidden',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'space-between',
        padding: '44px 52px',
        minWidth: 0,
      }}>

        {/* Photo background */}
        <img src={HERO_IMG} alt="" style={{
          position: 'absolute', inset: 0, width: '100%', height: '100%',
          objectFit: 'cover', objectPosition: 'center 60%', pointerEvents: 'none',
        }} />
        {/* Dark gradient overlay — heavier at top & bottom, lighter in middle */}
        <div style={{
          position: 'absolute', inset: 0, pointerEvents: 'none',
          background: 'linear-gradient(to bottom, rgba(8,11,17,.82) 0%, rgba(8,11,17,.45) 40%, rgba(8,11,17,.55) 65%, rgba(8,11,17,.92) 100%)',
        }} />
        {/* Green tint wash */}
        <div style={{
          position: 'absolute', inset: 0, pointerEvents: 'none',
          background: 'rgba(10,40,30,.25)',
        }} />

        {/* Logo */}
        <div style={{ position: 'relative', display: 'flex', alignItems: 'center', gap: 12 }}>
          <div style={{
            width: 42, height: 42, borderRadius: 11,
            background: 'linear-gradient(135deg, #1a9d75, #0a6647)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            boxShadow: '0 0 28px rgba(26,157,117,.45)',
          }}>
            <Scan size={20} color="white" />
          </div>
          <span style={{ fontSize: 16, fontWeight: 700, color: '#e8edf5', letterSpacing: '-.01em' }}>Roald's Attendance Records (RAR)</span>
        </div>


        {/* Spacer to push testimonial to bottom */}
        <div style={{ flex: 1 }} />

        {/* Testimonial card pinned to bottom */}
        <div style={{
          position: 'relative',
          background: 'rgba(22,27,36,.75)',
          backdropFilter: 'blur(16px)',
          border: '1px solid rgba(26,157,117,.15)',
          borderRadius: 16,
          padding: '22px 24px',
          marginTop: 32,
        }}>
          {/* Quote mark */}
          <div style={{
            width: 30, height: 30, borderRadius: 8,
            background: 'rgba(26,157,117,.15)', border: '1px solid rgba(26,157,117,.3)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            marginBottom: 14, fontSize: 18, color: '#1a9d75', fontWeight: 900, lineHeight: 1,
          }}>"</div>
          <p style={{ fontSize: 13, color: '#8a95a3', lineHeight: 1.7, marginBottom: 14 }}>
            "Pogi! Parang yung adviser nyo lang."
          </p>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <div style={{
              width: 32, height: 32, borderRadius: '50%',
              background: 'linear-gradient(135deg, #1a9d75, #0a6647)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 13, fontWeight: 700, color: 'white',
            }}>M</div>
            <div>
              <div style={{ fontSize: 12, fontWeight: 700, color: '#c8d0dc' }}>Mark Cabatbat</div>
              <div style={{ fontSize: 11, color: '#4a5568' }}>Master Teacher, Computer Systems Servicing</div>
            </div>
          </div>
          {/* Bottom progress bar decoration */}
          <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: 3, borderRadius: '0 0 16px 16px', background: 'linear-gradient(90deg, #1a9d75, #0a6647)' }} />
        </div>

      </div>

      {/* ── RIGHT PANEL ── */}
      <div style={{
        width: 'min(480px, 45vw)',
        flexShrink: 0,
        background: '#0d1117',
        borderLeft: '1px solid rgba(255,255,255,.05)',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        padding: '60px 48px',
        position: 'relative',
        overflow: 'hidden',
      }}>

        {/* Subtle top accent line */}
        <div style={{
          position: 'absolute', top: 0, left: 48, right: 48, height: 1,
          background: 'linear-gradient(90deg, transparent, rgba(26,157,117,.4), transparent)',
        }} />

        <div style={{ width: '100%', maxWidth: 340, margin: '0 auto' }}>

          {/* Header */}
          <div style={{ marginBottom: 36 }}>
            <h2 style={{ fontSize: 28, fontWeight: 800, color: '#e8edf5', marginBottom: 6, letterSpacing: '-.025em' }}>
              Welcome back
            </h2>
            <p style={{ fontSize: 14, color: '#3d4a5c', lineHeight: 1.5 }}>Sign in to access your attendance portal</p>
          </div>

          {/* Error */}
          {error && (
            <div style={{
              display: 'flex', alignItems: 'center', gap: 10,
              padding: '11px 14px', borderRadius: 10,
              background: 'rgba(224,85,85,.08)', border: '1px solid rgba(224,85,85,.2)',
              marginBottom: 24, fontSize: 13, color: '#f87171',
            }}>
              <AlertCircle size={14} style={{ flexShrink: 0 }} />
              {error}
            </div>
          )}

          {/* Form */}
          <form onSubmit={submit} style={{ display: 'flex', flexDirection: 'column', gap: 20, textAlign: 'left' }}>

            <div>
              <label style={{
                display: 'block', fontSize: 11, fontWeight: 600,
                letterSpacing: '.08em', textTransform: 'uppercase',
                color: '#3d4a5c', marginBottom: 8, textAlign: 'left',
              }}>Username</label>
              <input
                name="username" value={form.username} onChange={handle}
                autoComplete="username" required placeholder="Enter your username"
                style={{
                  width: '100%', padding: '13px 16px', borderRadius: 10,
                  background: 'rgba(255,255,255,.03)', border: '1px solid rgba(255,255,255,.07)',
                  color: '#e8edf5', fontSize: 14, outline: 'none', boxSizing: 'border-box',
                  transition: 'border-color .2s, background .2s',
                }}
                onFocus={e => { e.target.style.borderColor = 'rgba(26,157,117,.55)'; e.target.style.background = 'rgba(26,157,117,.04)' }}
                onBlur={e => { e.target.style.borderColor = 'rgba(255,255,255,.07)'; e.target.style.background = 'rgba(255,255,255,.03)' }}
              />
            </div>

            <div>
              <label style={{
                display: 'block', fontSize: 11, fontWeight: 600,
                letterSpacing: '.08em', textTransform: 'uppercase',
                color: '#3d4a5c', marginBottom: 8, textAlign: 'left',
              }}>Password</label>
              <div style={{ position: 'relative' }}>
                <input
                  name="password" type={show ? 'text' : 'password'} value={form.password} onChange={handle}
                  autoComplete="current-password" required placeholder="Enter your password"
                  style={{
                    width: '100%', padding: '13px 44px 13px 16px', borderRadius: 10,
                    background: 'rgba(255,255,255,.03)', border: '1px solid rgba(255,255,255,.07)',
                    color: '#e8edf5', fontSize: 14, outline: 'none', boxSizing: 'border-box',
                    transition: 'border-color .2s, background .2s',
                  }}
                  onFocus={e => { e.target.style.borderColor = 'rgba(26,157,117,.55)'; e.target.style.background = 'rgba(26,157,117,.04)' }}
                  onBlur={e => { e.target.style.borderColor = 'rgba(255,255,255,.07)'; e.target.style.background = 'rgba(255,255,255,.03)' }}
                />
                <button type="button" onClick={() => setShow(v => !v)} style={{
                  position: 'absolute', right: 14, top: '50%', transform: 'translateY(-50%)',
                  background: 'none', border: 'none', cursor: 'pointer', color: '#3d4a5c', padding: 0, display: 'flex',
                }}>
                  {show ? <EyeOff size={15} /> : <Eye size={15} />}
                </button>
              </div>
            </div>

            <button type="submit" disabled={loading} style={{
              marginTop: 4, width: '100%', padding: '14px 20px', borderRadius: 10,
              background: loading ? '#0e6644' : 'linear-gradient(135deg, #1a9d75 0%, #0c6644 100%)',
              color: 'white', fontSize: 14, fontWeight: 700, border: 'none',
              cursor: loading ? 'wait' : 'pointer', letterSpacing: '.01em',
              display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8,
              boxShadow: loading ? 'none' : '0 6px 28px rgba(26,157,117,.3)',
              transition: 'all .2s',
            }}>
              {loading ? 'Signing in…' : <><span>Sign In</span><ArrowRight size={15} /></>}
            </button>

          </form>

          {/* Simple divider line */}
          <div style={{ height: 1, background: 'rgba(255,255,255,.05)', margin: '28px 0 0' }} />

        </div>

        {/* Footer */}
        <p style={{ position: 'absolute', bottom: 24, left: 0, right: 0, textAlign: 'center', fontSize: 11, color: '#1e2530' }}>
          RAR Attendance Records System © {new Date().getFullYear()}
        </p>

      </div>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@400;500;600;700;800&display=swap');
        input::placeholder { color: #252e3d; }
        * { margin: 0; padding: 0; }
      `}</style>
    </div>
  )
}